import{_ as t,o,c as a,a3 as s}from"./chunks/framework.DACwFHq9.js";const h=JSON.parse('{"title":"Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"release-notes.md","filePath":"release-notes.md","lastUpdated":1784354374000}'),n={name:"release-notes.md"};function r(i,e,l,d,c,p){return o(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="release-notes" tabindex="-1">Release Notes <a class="header-anchor" href="#release-notes" aria-label="Permalink to &quot;Release Notes&quot;">​</a></h1><h2 id="_2026-07-17-latest" tabindex="-1">2026-07-17 (latest) <a class="header-anchor" href="#_2026-07-17-latest" aria-label="Permalink to &quot;2026-07-17 (latest)&quot;">​</a></h2><h3 id="new-features" tabindex="-1">New features <a class="header-anchor" href="#new-features" aria-label="Permalink to &quot;New features&quot;">​</a></h3><ul><li><p><strong>Keyboard Tab Switching</strong> — switch between open tabs using <code>Ctrl+Tab</code> (next) and <code>Ctrl+Shift+Tab</code> (previous).</p></li><li><p><strong>Copy Link Path</strong> — right-click on active tabs or dashboard document list items to copy the workspace-relative path for note referencing.</p></li><li><p><strong>Preview Link Hover overlay</strong> — hover over any link in note previews to open a popover with <strong>Copy</strong> and <strong>Navigate</strong> options (with icons). Direct link clicks are disabled to prevent accidental navigation jumps.</p></li><li><p><strong>Dismissible Toasts &amp; Undo actions</strong> — notification toasts now include an <code>X</code> dismiss button, and applying markdown quick fixes prompts an <strong>Undo</strong> toast to quickly revert changes.</p></li><li><p><strong>Always-Visible Workspace Sidebar</strong> — the dashboard rail containing recent notes, favorites, and open tasks remains visible when navigating workspace subfolders, preventing layout shifts and keeping dashboard information at hand.</p></li><li><p><strong>Improved Contrast on Colored Items</strong> — extracted dynamic inline styling into a semantic <code>.custom-colored-item</code> CSS class, ensuring document text, icons, and action chips dynamically scale contrast and remain highly readable when custom card/tab colors are applied.</p></li><li><p><strong>Draw.io Solid Background Exports</strong> — saves of Draw.io diagrams now export with a solid white background in PNG files, preventing poorly contrasted layouts under dark theme previews.</p></li><li><p><strong>Modal Corner Radius Standardization</strong> — custom modal borders consistently use <code>--radius-lg</code> (<code>6px</code>) to match standard dialog overlays.</p></li><li><p><strong>Centralized CSS Keyframes</strong> — common animations like <code>spin</code> and <code>modal-pop</code> are centralized in <code>base.css</code> to reduce code repetition.</p></li><li><p><strong>Double-click to open row</strong> — table list items in document dashboard now open immediately on double-click.</p></li><li><p><strong>Validation Banner Auto-Hide</strong> — the validation banner at the top of the editor is completely hidden when there are no issues.</p></li><li><p><strong>Spacing Token Normalization</strong> — dashboard panels and bars now use design system space tokens (<code>var(--space-4)</code> and <code>var(--space-5)</code>) for consistent alignments.</p></li></ul><hr><h2 id="_2026-07-11" tabindex="-1">2026-07-11 <a class="header-anchor" href="#_2026-07-11" aria-label="Permalink to &quot;2026-07-11&quot;">​</a></h2><ul><li><strong>Inline markdown table editor</strong> — placing the cursor inside a markdown table now opens a focused grid editor for direct cell/header updates.</li></ul><h3 id="refinements" tabindex="-1">Refinements <a class="header-anchor" href="#refinements" aria-label="Permalink to &quot;Refinements&quot;">​</a></h3><ul><li><strong>Compact table actions</strong> — row/column controls now use labeled compact action chips for quicker recognition and less visual noise.</li><li><strong>Table edit interaction flow</strong> — deleting rows/columns keeps editing context active instead of dropping back to the main editor.</li><li><strong>Table formatting preservation</strong> — same-shape table edits now preserve the original table style (spacing and delimiter style) where possible.</li></ul><h3 id="fixes" tabindex="-1">Fixes <a class="header-anchor" href="#fixes" aria-label="Permalink to &quot;Fixes&quot;">​</a></h3><ul><li><strong>Escaped content safety</strong> — table parsing now preserves escaped pipes and plain backslashes in cell content (including Windows-style paths).</li><li><strong>Scroll behavior during table edits</strong> — background scrolling is disabled while table editing is active; table content scrolling remains within the editor panel.</li></ul><hr><h2 id="_2026-07-03-latest" tabindex="-1">2026-07-03 (latest) <a class="header-anchor" href="#_2026-07-03-latest" aria-label="Permalink to &quot;2026-07-03 (latest)&quot;">​</a></h2><h3 id="new-features-1" tabindex="-1">New features <a class="header-anchor" href="#new-features-1" aria-label="Permalink to &quot;New features&quot;">​</a></h3><ul><li><strong>Open Workspace in VS Code</strong> — the landing <strong>File</strong> menu now includes <strong>Open Workspace in VS Code</strong> (<code>Ctrl/Cmd + Shift + O</code>). Opens the active workspace folder directly in VS Code, or falls back to the system default app.</li><li><strong>Reveal Workspace in File Explorer</strong> — the landing <strong>File</strong> menu now includes <strong>Reveal Workspace in File Explorer</strong> (<code>Ctrl/Cmd + Shift + J</code>). Opens the workspace folder in the native system file browser.</li><li><strong>Web menu</strong> — a new top-level <strong>Web</strong> menu (<code>Ctrl/Cmd + Shift + W</code>) provides one-click access to the project website (landing screen) or the current note&#39;s website view (note screen).</li><li><strong>Custom dropdown controls</strong> — all select/dropdown controls across the app have been replaced with a fully custom listbox component. The new control supports grouped options, keyboard navigation (arrow keys, Home, End, Enter, Escape), selected-state checkmarks, and focus-aware close behaviour.</li></ul><h3 id="refinements-1" tabindex="-1">Refinements <a class="header-anchor" href="#refinements-1" aria-label="Permalink to &quot;Refinements&quot;">​</a></h3><ul><li><strong>Form focus styles</strong> — focus indicators across all inputs, selects, and textareas have been softened to a subtle border tint and <code>2px</code> halo for a more professional desktop feel.</li><li><strong>Continue Writing panel</strong> — now shows only the single most recently edited note instead of a list, making it faster to resume work.</li><li><strong>Task hover popover</strong> — the note-level task summary popover now sizes to the available viewport height before showing a scrollbar.</li><li><strong>Note detail topbar consistency</strong> — breadcrumb chips, task summary, save status, and action controls now use aligned heights and shared corner radius styling for a cleaner, unified row.</li></ul><h3 id="fixes-1" tabindex="-1">Fixes <a class="header-anchor" href="#fixes-1" aria-label="Permalink to &quot;Fixes&quot;">​</a></h3><ul><li><strong>Workspace switch website refresh</strong> — opening project website view after changing workspace now reflects the current workspace immediately instead of reusing stale scope from the previous folder.</li><li><strong>Task summary accessibility semantics</strong> — the topbar task summary trigger now uses button semantics with screen-reader state attributes for improved accessibility.</li></ul><hr><h2 id="_2026-07-03" tabindex="-1">2026-07-03 <a class="header-anchor" href="#_2026-07-03" aria-label="Permalink to &quot;2026-07-03&quot;">​</a></h2><p>This release focuses on documentation accuracy, shortcut clarity, and in-app help coverage.</p><h3 id="documentation-updates" tabindex="-1">Documentation updates <a class="header-anchor" href="#documentation-updates" aria-label="Permalink to &quot;Documentation updates&quot;">​</a></h3><ul><li>Updated user docs to match current UI labels such as <strong>Open Workspace</strong> and <strong>Help Center</strong></li><li>Added a dedicated <strong>Settings Reference</strong> page</li><li>Added an <strong>FAQ</strong> page</li><li>Added this <strong>Release Notes</strong> page and a repository <code>CHANGELOG.md</code></li></ul><h3 id="shortcut-updates" tabindex="-1">Shortcut updates <a class="header-anchor" href="#shortcut-updates" aria-label="Permalink to &quot;Shortcut updates&quot;">​</a></h3><ul><li>Resolved overlapping shortcut definitions for the command palette, AI palette, focus mode, and outline workflows</li><li>Expanded the in-app keyboard shortcuts guide to include context-specific shortcuts and usage notes</li></ul><h3 id="help-center-updates" tabindex="-1">Help Center updates <a class="header-anchor" href="#help-center-updates" aria-label="Permalink to &quot;Help Center updates&quot;">​</a></h3><ul><li>Added new Help Center entries for settings, FAQ, and release notes</li><li>Updated task and troubleshooting documentation to cover current workflows more accurately</li></ul><h2 id="notes-for-existing-users" tabindex="-1">Notes for existing users <a class="header-anchor" href="#notes-for-existing-users" aria-label="Permalink to &quot;Notes for existing users&quot;">​</a></h2><ul><li>If you learned older menu names such as <strong>Notes Folder</strong> or <strong>Documentation</strong>, use <strong>Open Workspace</strong> and <strong>Help Center</strong> instead.</li><li>If you used older overlapping shortcuts, open the keyboard guide once to confirm the current bindings.</li></ul>',30)])])}const g=t(n,[["render",r]]);export{h as __pageData,g as default};
